// Normalise l'entrée du Call n8n Workflow Tool — plusieurs formes selon n8n / LangChain :
// - { category: "wellness" } (structured tool)
// - { query: "{\"category\":\"wellness\"}" } (DynamicTool, JSON string)
// - { query: "shakes" } (string seule)
// - { query: { category: "coffee" } } (imbrication)
// Sortie : { category: "" | "wellness"|"energie"|"shakes"|"coffee" } pour queryReplacement Postgres.

const ALLOWED = new Set(['wellness', 'energie', 'shakes', 'coffee']);

function pickCategory(obj) {
  if (!obj || typeof obj !== 'object') return '';
  const c = obj.category;
  if (typeof c !== 'string') return '';
  const t = c.trim().toLowerCase();
  return ALLOWED.has(t) ? t : '';
}

const raw = $input.first().json ?? {};
let category = pickCategory(raw);

if (!category && raw.query != null) {
  const q = raw.query;
  if (typeof q === 'string') {
    const s = q.trim();
    if (s.startsWith('{')) {
      try {
        category = pickCategory(JSON.parse(s));
      } catch {
        category = '';
      }
    } else {
      const low = s.toLowerCase();
      category = ALLOWED.has(low) ? low : '';
    }
  } else if (typeof q === 'object') {
    category = pickCategory(q);
  }
}

return [{ json: { category } }];

// Formate la réponse du tool pour le LLM : liste compacte JSON.
const rows = $input.all().map((i) => i.json).filter((j) => j && j.slug != null && String(j.slug).length > 0);
if (rows.length === 0) {
  return [
    {
      json: {
        items: [],
        note:
          'Aucun produit actif dans la base (vue v_pessobot_menu vide) ou filtre sans résultat. Catégories : wellness, energie, shakes, coffee.',
      },
    },
  ];
}
return [{ json: { count: rows.length, items: rows } }];
